    MyNode() {
        // Both use default MutuallyExclusive group
        sub1_ = create_subscription<Msg>("topic1", 10, callback1);
        sub2_ = create_subscription<Msg>("topic2", 10, callback2);

        // callback1 and callback2 NEVER run concurrently
    }
};
```

