void execute(std::shared_ptr<GoalHandleFibonacci> goal_handle) {
    for (int i = 0; i < 100; ++i) {
        // Publish feedback
        goal_handle->publish_feedback(feedback);  // Client disconnected!

        std::this_thread::sleep_for(1s);
    }

    goal_handle->succeed(result);  // No one listening!
}

