#include "nav2_costmap_2d/layer.hpp"
#include "nav2_costmap_2d/layered_costmap.hpp"
#include "rclcpp/rclcpp.hpp"

namespace custom_costmap_layers
{

class KeepoutLayer : public nav2_costmap_2d::Layer
{
public:
    KeepoutLayer() = default;

    virtual void onInitialize() override
    {
        current_ = true;
        enabled_ = true;

        auto node = node_.lock();
        if (!node) {
            throw std::runtime_error("Failed to lock node");
        }

        // Declare parameters
        node->declare_parameter(name_ + ".keepout_zones", rclcpp::PARAMETER_STRING_ARRAY);

        // Get keepout zones
        // Format: "x,y,radius" for circular zones
        std::vector<std::string> zones =
            node->get_parameter(name_ + ".keepout_zones").as_string_array();

        for (const auto& zone_str : zones) {
            // Parse zone: "2.5,3.0,1.0" → x=2.5, y=3.0, radius=1.0
            std::stringstream ss(zone_str);
            std::string item;
            std::vector<double> values;

            while (std::getline(ss, item, ',')) {
                values.push_back(std::stod(item));
            }

            if (values.size() == 3) {
                KeepoutZone zone{values[0], values[1], values[2]};
                keepout_zones_.push_back(zone);

                RCLCPP_INFO(node->get_logger(),
                    "Added keepout zone: (%.2f, %.2f) radius %.2f",
                    zone.x, zone.y, zone.radius);
            }
        }
    }

    virtual void updateBounds(
        double /*robot_x*/, double /*robot_y*/, double /*robot_yaw*/,
        double* min_x, double* min_y, double* max_x, double* max_y) override
    {
        // Update bounds to cover all keepout zones
        for (const auto& zone : keepout_zones_) {
            *min_x = std::min(*min_x, zone.x - zone.radius);
            *min_y = std::min(*min_y, zone.y - zone.radius);
            *max_x = std::max(*max_x, zone.x + zone.radius);
            *max_y = std::max(*max_y, zone.y + zone.radius);
        }
    }

    virtual void updateCosts(
        nav2_costmap_2d::Costmap2D& master_grid,
        int min_i, int min_j, int max_i, int max_j) override
    {
        if (!enabled_) return;

        // Mark keepout zones as lethal
        for (int j = min_j; j < max_j; j++) {
            for (int i = min_i; i < max_i; i++) {
                // Get world coordinates
                double wx, wy;
                master_grid.mapToWorld(i, j, wx, wy);

                // Check if cell is inside any keepout zone
                for (const auto& zone : keepout_zones_) {
                    double dx = wx - zone.x;
                    double dy = wy - zone.y;
                    double dist = std::sqrt(dx*dx + dy*dy);

                    if (dist <= zone.radius) {
                        master_grid.setCost(i, j, nav2_costmap_2d::LETHAL_OBSTACLE);
                        break;
                    }
                }
            }
        }
    }

    virtual void reset() override {}

    virtual void onFootprintChanged() override {}

private:
    struct KeepoutZone {
        double x, y;      // Center position
        double radius;    // Zone radius
    };

    std::vector<KeepoutZone> keepout_zones_;
};

}  // namespace custom_costmap_layers

#include "pluginlib/class_list_macros.hpp"
PLUGINLIB_EXPORT_CLASS(custom_costmap_layers::KeepoutLayer, nav2_costmap_2d::Layer)

theory.full_text:
**Image Messages in ROS2:**

ROS2 uses standardized message types for images:

| Message Type | Package | Purpose | Use Case |
|--------------|---------|---------|----------|
| **sensor_msgs/Image** | sensor_msgs | Raw image data | Uncompressed images |
| **sensor_msgs/CompressedImage** | sensor_msgs | JPEG/PNG compressed | Bandwidth-limited networks |
| **sensor_msgs/CameraInfo** | sensor_msgs | Camera calibration | Undistortion, depth estimation |

**Why Compression Matters:**

```
Raw Image (640×480 RGB):
640 × 480 × 3 bytes = 921,600 bytes ≈ 900 KB per frame

At 30 FPS:
900 KB × 30 = 27 MB/s bandwidth!

JPEG Compressed:
~50-100 KB per frame
30 FPS = 1.5-3 MB/s bandwidth ✓
```

**Image Transport Library:**

ROS2 `image_transport` provides:
- Automatic compression/decompression
- Plugin system for different codecs (JPEG, PNG, H.264, Theora)
- Transparent transport (subscriber doesn't need to know encoding)

**Publisher with Compression:**

```cpp
#include <image_transport/image_transport.hpp>
#include <sensor_msgs/msg/image.hpp>

class CameraPublisher : public rclcpp::Node {
public:
    CameraPublisher() : Node("camera_pub") {
        // Create image transport publisher
        image_transport::ImageTransport it(shared_from_this());
        pub_ = it.advertise("camera/image", 1);

        // Automatically publishes to:
        // - /camera/image/raw (uncompressed)
        // - /camera/image/compressed (JPEG)
        // - /camera/image/theora (video codec)
    }

private:
    image_transport::Publisher pub_;
};
```

**Subscriber with Automatic Decompression:**

```cpp
class CameraSubscriber : public rclcpp::Node {
public:
    CameraSubscriber() : Node("camera_sub") {
        image_transport::ImageTransport it(shared_from_this());

        // Subscribes to best available transport
        sub_ = it.subscribe("camera/image", 1,
            std::bind(&CameraSubscriber::image_callback, this, std::placeholders::_1));
    }

private:
    void image_callback(const sensor_msgs::msg::Image::ConstSharedPtr& msg) {
        // Automatically decompressed regardless of transport
        RCLCPP_INFO(get_logger(), "Received image: %dx%d", msg->width, msg->height);
    }

    image_transport::Subscriber sub_;
};
```

