#include <gazebo/gazebo.hh>
#include <gazebo/physics/physics.hh>
#include <rclcpp/rclcpp.hpp>
#include <geometry_msgs/msg/wrench.hpp>

namespace gazebo {

class PushPlugin : public ModelPlugin {
public:
    PushPlugin() : ModelPlugin() {}

    void Load(physics::ModelPtr _model, sdf::ElementPtr _sdf) override {
        // Store model pointer
        model_ = _model;
        link_ = model_->GetLink("base_link");

        if (!link_) {
            gzerr << "Link 'base_link' not found!\n";
            return;
        }

        // Initialize ROS2
        if (!rclcpp::ok()) {
            rclcpp::init(0, nullptr);
        }

        node_ = rclcpp::Node::make_shared("push_plugin");

        // Subscribe to force commands
        force_sub_ = node_->create_subscription<geometry_msgs::msg::Wrench>(
            "/apply_force", 10,
            std::bind(&PushPlugin::OnForceMsg, this, std::placeholders::_1));

        // Spin in separate thread
        ros_thread_ = std::thread([this]() { rclcpp::spin(node_); });

        // Connect to world update event
        update_connection_ = event::Events::ConnectWorldUpdateBegin(
            std::bind(&PushPlugin::OnUpdate, this));

        gzmsg << "Push plugin loaded for model: " << model_->GetName() << "\n";
    }

    ~PushPlugin() {
        rclcpp::shutdown();
        if (ros_thread_.joinable()) {
            ros_thread_.join();
        }
    }

private:
    void OnForceMsg(const geometry_msgs::msg::Wrench::SharedPtr msg) {
        std::lock_guard<std::mutex> lock(mutex_);
        force_.Set(msg->force.x, msg->force.y, msg->force.z);
        torque_.Set(msg->torque.x, msg->torque.y, msg->torque.z);
        apply_force_ = true;
    }

    void OnUpdate() {
        std::lock_guard<std::mutex> lock(mutex_);

        if (apply_force_) {
            // Apply force to link
            link_->AddForce(force_);
            link_->AddTorque(torque_);

            // One-time application (or continuous if desired)
            apply_force_ = false;
        }
    }

    physics::ModelPtr model_;
    physics::LinkPtr link_;
    rclcpp::Node::SharedPtr node_;
    rclcpp::Subscription<geometry_msgs::msg::Wrench>::SharedPtr force_sub_;

    event::ConnectionPtr update_connection_;
    std::thread ros_thread_;
    std::mutex mutex_;

    ignition::math::Vector3d force_;
    ignition::math::Vector3d torque_;
    bool apply_force_ = false;
};

// Register plugin
GZ_REGISTER_MODEL_PLUGIN(PushPlugin)

}  // namespace gazebo

edge_cases.explanation:
**Scenario:**
`on_configure()` partially succeeds (loaded params, allocated some resources), then returns FAILURE. Resources leaked?

**Code:**
```cpp
CallbackReturn on_configure(const State &) override {
    // Allocate resource 1
    camera_ = std::make_shared<Camera>();
    camera_->open();  // ✅ Success

    // Allocate resource 2
    publisher_ = create_lifecycle_publisher<Image>("image", 10);  // ✅ Success

    // Validate config
    int fps = get_parameter("fps").as_int();
    if (fps > 60) {
        RCLCPP_ERROR(get_logger(), "FPS too high!");
        // ❌ Returning FAILURE - but camera_ still open! Leak!
        return CallbackReturn::FAILURE;
    }

    return CallbackReturn::SUCCESS;
}
```

**Why:**
Failed transition doesn't automatically clean up partial allocations.

**Solution 1 - Manual Cleanup on Failure:**

```cpp
CallbackReturn on_configure(const State &) override {
    try {
        camera_ = std::make_shared<Camera>();
        camera_->open();

        publisher_ = create_lifecycle_publisher<Image>("image", 10);

        int fps = get_parameter("fps").as_int();
        if (fps > 60) {
            // Clean up before returning failure
            camera_->close();
            camera_.reset();
            publisher_.reset();

            RCLCPP_ERROR(get_logger(), "FPS too high!");
            return CallbackReturn::FAILURE;
        }

        return CallbackReturn::SUCCESS;

    } catch (std::exception &e) {
        // Clean up on exception
        if (camera_) camera_->close();
        camera_.reset();
        publisher_.reset();

        RCLCPP_ERROR(get_logger(), "Config failed: %s", e.what());
        return CallbackReturn::ERROR;
    }
}
```

**Solution 2 - RAII Pattern:**

```cpp
class CameraWrapper {
    std::shared_ptr<Camera> cam_;
public:
    CameraWrapper() {
        cam_ = std::make_shared<Camera>();
        cam_->open();
    }

    ~CameraWrapper() {
        if (cam_) cam_->close();  // Auto-cleanup
    }

    Camera* get() { return cam_.get(); }
};

// In lifecycle node:
std::unique_ptr<CameraWrapper> camera_;

CallbackReturn on_configure(const State &) override {
    camera_ = std::make_unique<CameraWrapper>();  // Opens camera

    // If we return FAILURE, destructor auto-closes camera
    if (some_condition) {
        return CallbackReturn::FAILURE;  // ✅ Camera auto-closed
    }

    return CallbackReturn::SUCCESS;
}
```

**Interview Insight:**
Failed transitions don't auto-cleanup. Use RAII pattern (smart pointers, destructors) or explicit cleanup before returning FAILURE.

---

