#include "rclcpp/rclcpp.hpp"
#include "my_robot_interfaces/msg/battery_sensor.hpp"
#include <random>

class BatteryMonitor : public rclcpp::Node
{
public:
    BatteryMonitor() : Node("battery_monitor")
    {
        // Declare parameters
        declare_parameter("publish_rate", 10.0);
        declare_parameter("battery_id", "BAT001");

        auto rate = get_parameter("publish_rate").as_double();
        battery_id_ = get_parameter("battery_id").as_string();

        // Create publisher
        publisher_ = create_publisher<my_robot_interfaces::msg::BatterySensor>(
            "battery_status", 10);

        // Create timer
        timer_ = create_wall_timer(
            std::chrono::milliseconds(static_cast<int>(1000.0 / rate)),
            std::bind(&BatteryMonitor::publish_battery, this));

        // Initialize state
        voltage_ = 24.0;
        current_ = 0.0;
        percentage_ = 100.0;
        state_ = my_robot_interfaces::msg::BatterySensor::FULL;

        RCLCPP_INFO(get_logger(), "Battery monitor started: %s", battery_id_.c_str());
    }

private:
    void publish_battery()
    {
        // Simulate battery discharge
        if (state_ == my_robot_interfaces::msg::BatterySensor::DISCHARGING) {
            percentage_ -= 0.1;
            voltage_ = 20.0 + (percentage_ / 100.0) * 5.0;  // 20-25V range
            current_ = 2.0 + random_float(-0.5, 0.5);

            if (percentage_ <= 0.0) {
                percentage_ = 0.0;
                state_ = my_robot_interfaces::msg::BatterySensor::CRITICAL;
            } else if (percentage_ <= 20.0) {
                state_ = my_robot_interfaces::msg::BatterySensor::CRITICAL;
            }
        }

        // Create message
        auto msg = my_robot_interfaces::msg::BatterySensor();

        msg.header.stamp = now();
        msg.header.frame_id = "battery_link";

        msg.voltage = voltage_;
        msg.current = current_;
        msg.percentage = percentage_;
        msg.temperature = 25.0 + random_float(-2.0, 2.0);
        msg.state = state_;
        msg.is_charging = (state_ == my_robot_interfaces::msg::BatterySensor::CHARGING);
        msg.battery_id = battery_id_;

        publisher_->publish(msg);

        // Log status
        RCLCPP_INFO(get_logger(),
            "Battery: %.1f%% | %.2fV | %.2fA | %s",
            msg.percentage, msg.voltage, msg.current,
            state_to_string(msg.state).c_str());
    }

    std::string state_to_string(uint8_t state)
    {
        switch (state) {
            case my_robot_interfaces::msg::BatterySensor::CHARGING:
                return "CHARGING";
            case my_robot_interfaces::msg::BatterySensor::DISCHARGING:
                return "DISCHARGING";
            case my_robot_interfaces::msg::BatterySensor::FULL:
                return "FULL";
            case my_robot_interfaces::msg::BatterySensor::CRITICAL:
                return "CRITICAL";
            default:
                return "UNKNOWN";
        }
    }

    float random_float(float min, float max)
    {
        static std::random_device rd;
        static std::mt19937 gen(rd());
        std::uniform_real_distribution<float> dist(min, max);
        return dist(gen);
    }

    rclcpp::Publisher<my_robot_interfaces::msg::BatterySensor>::SharedPtr publisher_;
    rclcpp::TimerBase::SharedPtr timer_;

    std::string battery_id_;
    float voltage_;
    float current_;
    float percentage_;
    uint8_t state_;
};

int main(int argc, char** argv)
{
    rclcpp::init(argc, argv);
    rclcpp::spin(std::make_shared<BatteryMonitor>());
    rclcpp::shutdown();
    return 0;
}

edge_cases.explanation:
**Scenario:**

Robot is moving, hardware connection suddenly lost (cable unplugged, network drop):

```
t=0s:   Robot moving, joints at position [1.0, 0.5, 0.3]
t=5s:   Cable unplugged
        read() fails → what values in hw_positions_?
        write() fails → are commands sent?
t=6s:   Robot still moving? Stopped? Unknown state!
```

**Why:**
- USB cable disconnected
- Network timeout
- Hardware fault (motor driver failure)

**Problem:**

```cpp
hardware_interface::return_type read(...) override {
    try {
        read_joint_positions(hw_positions_);
    } catch (SerialException& e) {
        // ❌ Bad: Silently ignore error
        return hardware_interface::return_type::OK;  // Lie!
    }
}

// Controller gets stale data → continues sending commands to disconnected hardware
```

**Solution 1: Return Error on Failure**

```cpp
hardware_interface::return_type read(...) override {
    try {
        read_joint_positions(hw_positions_);
        read_joint_velocities(hw_velocities_);
        return hardware_interface::return_type::OK;

    } catch (SerialException& e) {
        RCLCPP_ERROR(get_logger(), "Hardware read failed: %s", e.what());
        return hardware_interface::return_type::ERROR;  // ✅ Report error
    }
}
```

**Effect:** Controller manager detects error → deactivates controllers → robot stops accepting commands.

**Solution 2: Use Lifecycle States**

```cpp
CallbackReturn on_error(const rclcpp_lifecycle::State &) override {
    RCLCPP_ERROR(get_logger(), "Hardware error! Emergency stop.");

    // Attempt to send stop command
    try {
        emergency_stop();
    } catch (...) {
        // Even emergency stop failed
    }

    // Close connection
    close_serial_port(serial_port_handle_);

    return CallbackReturn::SUCCESS;
}
```

**Solution 3: Watchdog Timer**

```cpp
std::chrono::steady_clock::time_point last_successful_read_;

hardware_interface::return_type read(...) override {
    try {
        read_joint_positions(hw_positions_);
        last_successful_read_ = std::chrono::steady_clock::now();
        return hardware_interface::return_type::OK;

    } catch (SerialException& e) {
        // Check if connection lost for too long
        auto now = std::chrono::steady_clock::now();
        auto duration = std::chrono::duration_cast<std::chrono::seconds>(
            now - last_successful_read_);

        if (duration.count() > 2) {  // > 2 seconds without successful read
            RCLCPP_ERROR(get_logger(), "Hardware connection lost!");
            return hardware_interface::return_type::ERROR;
        }

        return hardware_interface::return_type::OK;  // Tolerate brief failures
    }
}
```

**Interview Insight:**
Hardware connection failures must be detected and handled. Return ERROR from read()/write() to signal failure. Use lifecycle states for error handling. Implement watchdog timers to detect prolonged failures.

---

